#include <iostream>

class Engine {
    long long efficiency_;
public:
    explicit Engine(long long efficiency) : efficiency_(efficiency) {}
    long long distance(long long fuel) const { return efficiency_ * fuel; }
};
class Car {
    Engine engine_;
public:
    explicit Car(long long efficiency) : engine_(efficiency) {}
    long long range(long long fuel) const { return engine_.distance(fuel); }
};

int main() {
    long long efficiency{}, fuel{};
    if (!(std::cin >> efficiency >> fuel)) return 1;
    Car car(efficiency);
    std::cout << car.range(fuel) << '\n';
}
